1	use crate::message::Message;
2	use futures_util::StreamExt;
3	use reqwest::Client;
4	use serde::{Deserialize, Serialize};
5	use tokio::sync::mpsc;
6	use tokio_util::sync::CancellationToken;
7	
8	#[derive(Debug, Deserialize)]
9	pub struct OllamaModel {
10	    pub name: String,
11	}
12	
13	#[derive(Debug, Deserialize)]
14	struct OllamaTagsResponse {
15	    models: Vec<OllamaModel>,
16	}
17	
18	#[derive(Debug, Deserialize)]
19	struct OpenAIModel {
20	    id: String,
21	}
22	
23	#[derive(Debug, Deserialize)]
24	struct OpenAIModelsResponse {
25	    data: Vec<OpenAIModel>,
26	}
27	
28	#[derive(Serialize)]
29	struct ChatRequest {
30	    model: String,
31	    messages: Vec<Message>,
32	    stream: bool,
33	    #[serde(skip_serializing_if = "Option::is_none")]
34	    temperature: Option<f32>,
35	    #[serde(skip_serializing_if = "Option::is_none")]
36	    max_tokens: Option<u32>,
37	}
38	
39	#[derive(Deserialize)]
40	struct ChatChunk {
41	    choices: Option<Vec<ChunkChoice>>,
42	    usage: Option<Usage>,
43	}
44	
45	#[derive(Deserialize, Clone)]
46	pub struct Usage {
47	    pub prompt_tokens: Option<u32>,
48	    pub completion_tokens: Option<u32>,
49	    pub total_tokens: Option<u32>,
50	}
51	
52	#[derive(Deserialize)]
53	struct ChunkChoice {
54	    delta: Option<Delta>,
55	}
56	
57	#[derive(Deserialize)]
58	struct Delta {
59	    content: Option<String>,
60	}
61	
62	pub enum StreamEvent {
63	    Token(String),
64	    Done,
65	    Error(String),
66	    UsageInfo(Usage),
67	}
68	
69	const MAX_ERROR_BODY: usize = 4096;
70	const MAX_STREAM_BUFFER: usize = 1024 * 1024; // 1MB
71	
72	pub async fn fetch_models(base_url: &str, api_key: Option<&str>) -> Result<Vec<String>, String> {
73	    let client = Client::new();
74	    let url = base_url.trim_end_matches('/');
75	
76	    // Try OpenAI-standard /v1/models first (works for OpenRouter, LM Studio, vLLM, etc.)
77	    let models_url = if url.ends_with("/v1") {
78	        format!("{url}/models")
79	    } else {
80	        format!("{url}/v1/models")
81	    };
82	
83	    let mut request = client.get(&models_url);
84	    if let Some(key) = api_key {
85	        request = request.bearer_auth(key);
86	    }
87	
88	    if let Ok(resp) = request.send().await {
89	        if resp.status().is_success() {
90	            if let Ok(openai_resp) = resp.json::<OpenAIModelsResponse>().await {
91	                let models: Vec<String> = openai_resp.data.into_iter().map(|m| m.id).collect();
92	                if !models.is_empty() {
93	                    return Ok(models);
94	                }
95	            }
96	        }
97	    }
98	
99	    // Fall back to Ollama /api/tags
100	    let api_base = url.trim_end_matches("/v1");
101	    let resp = client
102	        .get(format!("{api_base}/api/tags"))
103	        .send()
104	        .await
105	        .map_err(|e| format!("Failed to fetch models: {e}"))?;
106	
107	    let tags: OllamaTagsResponse = resp
108	        .json()
109	        .await
110	        .map_err(|e| format!("Failed to parse models: {e}"))?;
111	
112	    Ok(tags.models.into_iter().map(|m| m.name).collect())
113	}
114	
115	pub fn stream_chat(
116	    base_url: String,
117	    model: String,
118	    messages: Vec<Message>,
119	    temperature: Option<f32>,
120	    max_tokens: Option<u32>,
121	    api_key: Option<String>,
122	    tx: mpsc::UnboundedSender<StreamEvent>,
123	    cancel: CancellationToken,
124	) {
125	    tokio::spawn(async move {
126	        let client = Client::new();
127	        let url = format!("{}/chat/completions", base_url.trim_end_matches('/'));
128	
129	        let req = ChatRequest {
130	            model,
131	            messages,
132	            stream: true,
133	            temperature,
134	            max_tokens,
135	        };
136	
137	        let mut request = client.post(&url).json(&req);
138	        if let Some(key) = &api_key {
139	            request = request.bearer_auth(key);
140	        }
141	        if base_url.contains("openrouter.ai") {
142	            request = request
143	                .header("HTTP-Referer", "https://github.com/hhheath/hChat")
144	                .header("X-Title", "hChat");
145	        }
146	
147	        let resp = match request.send().await {
148	            Ok(r) => r,
149	            Err(e) => {
150	                let _ = tx.send(StreamEvent::Error(format!("Request failed: {e}")));
151	                return;
152	            }
153	        };
154	
155	        if !resp.status().is_success() {
156	            let status = resp.status();
157	            // Limit error body size to prevent OOM
158	            let body = resp
159	                .bytes()
160	                .await
161	                .map(|b| {
162	                    let truncated = &b[..b.len().min(MAX_ERROR_BODY)];
163	                    String::from_utf8_lossy(truncated).into_owned()
164	                })
165	                .unwrap_or_default();
166	            let _ = tx.send(StreamEvent::Error(format!("{status}: {body}")));
167	            return;
168	        }
169	
170	        let mut stream = resp.bytes_stream();
171	        // Use a byte buffer to handle UTF-8 sequences split across chunks
172	        let mut raw_buf: Vec<u8> = Vec::new();
173	
174	        loop {
175	            tokio::select! {
176	                _ = cancel.cancelled() => {
177	                    let _ = tx.send(StreamEvent::Done);
178	                    return;
179	                }
180	                chunk = stream.next() => {
181	                    let Some(chunk) = chunk else {
182	                        let _ = tx.send(StreamEvent::Done);
183	                        return;
184	                    };
185	
186	                    let bytes = match chunk {
187	                        Ok(b) => b,
188	                        Err(e) => {
189	                            let _ = tx.send(StreamEvent::Error(format!("Stream error: {e}")));
190	                            return;
191	                        }
192	                    };
193	
194	                    raw_buf.extend_from_slice(&bytes);
195	
196	                    if raw_buf.len() > MAX_STREAM_BUFFER {
197	                        let _ = tx.send(StreamEvent::Error("Stream buffer overflow".to_string()));
198	                        return;
199	                    }
200	
201	                    // Find the last valid UTF-8 boundary to avoid splitting multi-byte chars
202	                    let valid_up_to = match std::str::from_utf8(&raw_buf) {
203	                        Ok(_) => raw_buf.len(),
204	                        Err(e) => e.valid_up_to(),
205	                    };
206	
207	                    if valid_up_to == 0 {
208	                        continue;
209	                    }
210	
211	                    // Safe: we just validated this range is valid UTF-8
212	                    let text = std::str::from_utf8(&raw_buf[..valid_up_to]).unwrap();
213	                    let mut remaining_start = 0;
214	
215	                    for line_end in memchr_newlines(text) {
216	                        let line = text[remaining_start..line_end].trim();
217	                        remaining_start = line_end + 1;
218	
219	                        if line.is_empty() || line.starts_with(':') {
220	                            continue;
221	                        }
222	
223	                        let data = if let Some(d) = line.strip_prefix("data: ") {
224	                            d.trim()
225	                        } else {
226	                            continue;
227	                        };
228	
229	                        if data == "[DONE]" {
230	                            let _ = tx.send(StreamEvent::Done);
231	                            return;
232	                        }
233	
234	                        if let Ok(chunk) = serde_json::from_str::<ChatChunk>(data) {
235	                            if let Some(choices) = chunk.choices {
236	                                for choice in choices {
237	                                    if let Some(delta) = choice.delta
238	                                        && let Some(content) = delta.content {
239	                                            let _ = tx.send(StreamEvent::Token(content));
240	                                        }
241	                                }
242	                            }
243	                            if let Some(usage) = chunk.usage {
244	                                let _ = tx.send(StreamEvent::UsageInfo(usage));
245	                            }
246	                        }
247	                    }
248	
249	                    // Keep unprocessed bytes (incomplete line + any trailing invalid UTF-8)
250	                    let consumed = remaining_start.min(valid_up_to);
251	                    raw_buf = raw_buf[consumed..].to_vec();
252	                }
253	            }
254	        }
255	    });
256	}
257	
258	/// Find all newline positions in a string slice
259	fn memchr_newlines(s: &str) -> Vec<usize> {
260	    s.bytes()
261	        .enumerate()
262	        .filter_map(|(i, b)| if b == b'\n' { Some(i) } else { None })
263	        .collect()
264	}
