use crate::api::{self, StreamEvent, Usage};
use crate::config::{Config, Endpoint};
use crate::message::{Message, Role};
use crate::storage::Storage;
use eframe::egui;
use egui_commonmark::{CommonMarkCache, CommonMarkViewer};
use tokio::sync::mpsc;
use tokio_util::sync::CancellationToken;

pub struct ChatApp {
    messages: Vec<Message>,
    input: String,
    base_url: String,
    models: Vec<String>,
    selected_model: usize,
    streaming: bool,
    rx: Option<mpsc::UnboundedReceiver<StreamEvent>>,
    /// Separate channel for model fetching so it doesn't conflict with chat streaming
    models_rx: Option<mpsc::UnboundedReceiver<StreamEvent>>,
    cancel_token: Option<CancellationToken>,
    runtime: tokio::runtime::Runtime,
    models_loading: bool,
    error: Option<String>,
    system_prompt: String,
    temperature: f32,
    max_tokens: u32,
    use_max_tokens: bool,
    dark_mode: bool,
    commonmark_cache: CommonMarkCache,
    editing_message: Option<usize>,
    edit_buffer: String,
    show_settings: bool,
    // Persistence
    storage: Storage,
    current_conversation_id: Option<i64>,
    conversation_list: Vec<(i64, String)>,
    show_sidebar: bool,
    // Search
    search_query: String,
    search_results: Vec<(i64, String, String)>,
    show_search: bool,
    // Endpoints
    saved_endpoints: Vec<Endpoint>,
    show_endpoints: bool,
    new_endpoint: String,
    new_endpoint_key: String,
    // Token usage
    last_usage: Option<Usage>,
    // Rename
    renaming_conversation: Option<i64>,
    rename_buffer: String,
    // Config
    config: Config,
}

impl ChatApp {
    pub fn new(cc: &eframe::CreationContext<'_>, config: Config) -> Self {
        configure_fonts(&cc.egui_ctx, &config);
        apply_theme(&cc.egui_ctx, config.dark_mode);
        cc.egui_ctx.set_pixels_per_point(config.ui_scale);

        let runtime = tokio::runtime::Runtime::new().expect("Failed to create tokio runtime");
        let storage = Storage::new();
        let conversation_list = storage
            .list_conversations()
            .into_iter()
            .map(|c| (c.id, c.title))
            .collect();

        let base_url = config.default_endpoint.clone();

        let mut app = Self {
            messages: Vec::new(),
            input: String::new(),
            base_url: base_url.clone(),
            models: Vec::new(),
            selected_model: 0,
            streaming: false,
            rx: None,
            models_rx: None,
            cancel_token: None,
            runtime,
            models_loading: true,
            error: None,
            system_prompt: config.system_prompt.clone(),
            temperature: config.temperature,
            max_tokens: config.max_tokens,
            use_max_tokens: config.use_max_tokens,
            dark_mode: config.dark_mode,
            commonmark_cache: CommonMarkCache::default(),
            editing_message: None,
            edit_buffer: String::new(),
            show_settings: false,
            storage,
            current_conversation_id: None,
            conversation_list,
            show_sidebar: true,
            search_query: String::new(),
            search_results: Vec::new(),
            show_search: false,
            saved_endpoints: config.saved_endpoints.clone(),
            show_endpoints: false,
            new_endpoint: String::new(),
            new_endpoint_key: String::new(),
            last_usage: None,
            renaming_conversation: None,
            rename_buffer: String::new(),
            config,
        };

        app.fetch_models();
        app
    }

    fn fetch_models(&mut self) {
        let base_url = self.base_url.clone();
        let api_key = self.current_api_key().map(|s| s.to_string());
        let (tx, rx) = mpsc::unbounded_channel();

        self.runtime.spawn(async move {
            match api::fetch_models(&base_url, api_key.as_deref()).await {
                Ok(models) => {
                    if let Ok(json) = serde_json::to_string(&models) {
                        let _ = tx.send(StreamEvent::Token(json));
                    }
                }
                Err(e) => {
                    let _ = tx.send(StreamEvent::Error(e));
                }
            }
            let _ = tx.send(StreamEvent::Done);
        });

        self.models_loading = true;
        self.models_rx = Some(rx);
    }

    fn selected_model_name(&self) -> &str {
        self.models
            .get(self.selected_model)
            .map(|s| s.as_str())
            .unwrap_or("(no models)")
    }

    fn current_api_key(&self) -> Option<&str> {
        self.saved_endpoints
            .iter()
            .find(|ep| ep.url == self.base_url)
            .and_then(|ep| ep.api_key.as_deref())
    }

    fn new_conversation(&mut self) {
        if self.streaming {
            self.stop_streaming();
        }
        self.save_current();
        self.messages.clear();
        self.current_conversation_id = None;
        self.error = None;
        self.last_usage = None;
    }

    fn save_current(&mut self) {
        if self.messages.is_empty() {
            return;
        }

        match self.current_conversation_id {
            Some(id) => {
                self.storage.save_messages(id, &self.messages);
            }
            None => {
                let title = self
                    .messages
                    .iter()
                    .find(|m| m.role == Role::User)
                    .map(|m| {
                        let t = m.content.trim();
                        if t.len() > 50 {
                            // Find a char boundary for truncation
                            let end = t
                                .char_indices()
                                .take_while(|(i, _)| *i <= 47)
                                .last()
                                .map(|(i, c)| i + c.len_utf8())
                                .unwrap_or(47);
                            format!("{}...", &t[..end])
                        } else {
                            t.to_string()
                        }
                    })
                    .unwrap_or_else(|| "New chat".to_string());

                let id = self.storage.create_conversation(&title);
                self.storage.save_messages(id, &self.messages);
                self.current_conversation_id = Some(id);
            }
        };

        self.refresh_conversation_list();

