+use serde::de::Deserializer;
 use serde::{Deserialize, Serialize};
 use std::fs;
 use std::io;
 use std::path::PathBuf;

+#[cfg(unix)]
+fn set_dir_permissions(path: &std::path::Path) {
+    use std::os::unix::fs::PermissionsExt;
+    let _ = fs::set_permissions(path, fs::Permissions::from_mode(0o700));
+}
+
 const MAX_CONFIG_SIZE: u64 = 1_048_576; // 1 MB

+#[derive(Serialize, Clone, Debug)]
+pub struct Endpoint {
+    pub url: String,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub api_key: Option<String>,
+}
+
+impl<'de> Deserialize<'de> for Endpoint {
+    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
+    where
+        D: Deserializer<'de>,
+    {
+        #[derive(Deserialize)]
+        #[serde(untagged)]
+        enum EndpointRepr {
+            Simple(String),
+            Full {
+                url: String,
+                api_key: Option<String>,
+            },
+        }
+
+        match EndpointRepr::deserialize(deserializer)? {
+            EndpointRepr::Simple(url) => Ok(Endpoint {
+                url,
+                api_key: None,
+            }),
+            EndpointRepr::Full { url, api_key } => Ok(Endpoint { url, api_key }),
+        }
+    }
+}
+
+impl Endpoint {
+    pub fn new(url: impl Into<String>) -> Self {
+        Self {
+            url: url.into(),
+            api_key: None,
+        }
+    }
+}
